def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 6):
            weight = (6 - j) / 15
            partial_ratio = ratio ** j
            score += weight * partial_ratio
        if capacity < item * 1.5:
            score *= 1.2
            for k in range(1, 4):
                score += (k / 10) * (ratio ** k)
        elif capacity > item * 3:
            score *= 0.8
            for k in range(3, 6):
                if k % 2 == 0:
                    score -= (k / 20) * (ratio ** k)
                else:
                    score += (k / 25) * (ratio ** k)
        else:
            for k in range(1, 5):
                if k == 3:
                    score += (k / 30) * (ratio ** k)
                else:
                    score -= (k / 40) * (ratio ** k)
        if score < 0:
            score = 0
        priorities[i] = score
    return priorities
